Trigger.TriggerText:
BEGIN
    SET_WINDOW_PROPERTY(FORMS_MDI_WINDOW, TITLE, 'HRMS Login');
    SET_WINDOW_PROPERTY('WIN_LOGIN', WINDOW_STATE, NORMAL);
    GO_ITEM('LOGIN.USERNAME');
END;

DECLARE
    v_session_id NUMBER;
BEGIN
    :LOGIN.ERROR_MSG := NULL;

    IF :LOGIN.USERNAME IS NULL OR :LOGIN.PASSWORD IS NULL THEN
        :LOGIN.ERROR_MSG := 'Please enter username and password.';
        RAISE FORM_TRIGGER_FAILURE;
    END IF;

    BEGIN
        v_session_id := PKG_SECURITY.authenticate(
            :LOGIN.USERNAME,
            :LOGIN.PASSWORD,
            GET_APPLICATION_PROPERTY(CLIENT_HOST)
        );

        -- Store session info in global variables
        :GLOBAL.session_id := TO_CHAR(v_session_id);
        :GLOBAL.current_user := :LOGIN.USERNAME;

        -- Get employee details
        SELECT EMP_ID INTO :GLOBAL.current_emp_id
        FROM EMPLOYEES
        WHERE UPPER(EMAIL) = UPPER(:LOGIN.USERNAME)
        AND EMPLOYMENT_STATUS = 'ACTIVE'
        AND ROWNUM = 1;

        -- Open main menu
        OPEN_FORM('HRMS_MENU', ACTIVATE, SESSION);

    EXCEPTION
        WHEN OTHERS THEN
            :LOGIN.ERROR_MSG := 'Invalid username or password.';
            :LOGIN.PASSWORD := NULL;
            GO_ITEM('LOGIN.PASSWORD');
            RAISE FORM_TRIGGER_FAILURE;
    END;
END;

BEGIN
    IF :SYSTEM.CURSOR_ITEM = 'LOGIN.PASSWORD' THEN
        DO_KEY('WHEN-BUTTON-PRESSED');
    ELSE
        NEXT_ITEM;
    END IF;
END;
